module my.module {
  exports com.example;
  requires java.base;
}

// com/example paketindəki sinif
package com.example;

public class Main {
  public static void main(String[] args) {
    String message = "Salam, Modul Sistemi!";
    System.out.println(message);
  }
}
// Çıxış: Salam, Modul Sistemi!

module app.module {
  requires my.module;
}

// app/module paketindəki sinif
package app.module;

import com.example.Main;

public class App {
  public static void main(String[] args) {
    Main main = new Main();
    main.main(args);
  }
}
// Çıxış: Salam, Modul Sistemi!

